import React from "react"

class User extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            users: [
                {
                    id: 1
                }
            ]
        }
    }
    render() {
        return (
            <div>
                {this.users.map((item) => (<div key={item.id} className="users">
                    <h3>{item.firstname}</h3>
                </div>))}
            </div>
        )
    }
}



export default User
